examples.fromCode:
public class Resource implements AutoCloseable {
    public Resource() { System.out.println("Acquired"); }
    public void use() { System.out.println("Using"); }
    @Override
    public void close() { System.out.println("Released"); }
}
// Usage
try (Resource r = new Resource()) {
    r.use();
}

