#include <iostream>

class Resource {
public:
    Resource() { std::cout << "Acquired\n"; }
    ~Resource() { std::cout << "Released\n"; }
    void use() { std::cout << "Using\n"; }
};
// Usage
{
    Resource r;
    r.use();
} // Automatically destructed here

